const express = require('express');
const bodyParser = require('body-parser');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(bodyParser.json());

const plugins = [];

// Load plugins from configuration files or environment variables
function loadPlugins() {
    const pluginFiles = process.env.PLUGIN_FILES ? process.env.PLUGIN_FILES.split(',') : [];
    pluginFiles.forEach(file => {
        const pluginPath = path.resolve(__dirname, file);
        if (fs.existsSync(pluginPath)) {
            const plugin = require(pluginPath);
            plugins.push(plugin);
        }
    });
}

// Middleware to apply plugins
app.use((req, res, next) => {
    plugins.forEach(plugin => {
        if (typeof plugin.modifyRequest === 'function') {
            plugin.modifyRequest(req);
        }
    });
    next();
});

// Example route
app.get('/api/data', (req, res) => {
    let responseData = { message: 'Hello, World!' };
    plugins.forEach(plugin => {
        if (typeof plugin.modifyResponse === 'function') {
            responseData = plugin.modifyResponse(responseData);
        }
    });
    res.json(responseData);
});

// Load plugins on startup
loadPlugins();

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`API Gateway running on port ${PORT}`);
});

