const securePlugins = [];

// Securely load plugins with validation
function loadSecurePlugins() {
    const pluginFiles = process.env.PLUGIN_FILES ? process.env.PLUGIN_FILES.split(',') : [];
    pluginFiles.forEach(file => {
        const pluginPath = path.resolve(__dirname, file);
        if (fs.existsSync(pluginPath) && isValidPlugin(pluginPath)) {
            const plugin = require(pluginPath);
            securePlugins.push(plugin);
        }
    });
}

// Validate plugin structure
function isValidPlugin(pluginPath) {
    const plugin = require(pluginPath);
    return plugin && typeof plugin.modifyRequest === 'function' && typeof plugin.modifyResponse === 'function';
}

// Middleware to apply secure plugins
